from pathlib import Path
import json, sys, re

def current_quarter(year, month):
    return f"{year}-Q{(month - 1) // 3 + 1}"

def parse_quarter(s):
    m = re.match(r'(\d{4})-Q([1-4])', s or '')
    return (int(m.group(1)), int(m.group(2))) if m else (0, 0)

def quarters_ago(label, current):
    y, q = parse_quarter(label)
    cy, cq = parse_quarter(current)
    return (cy - y) * 4 + (cq - q)

def find_stale(dashboard_root: str, quarter: str, threshold: int = 1):
    stale = []
    for owners_file in Path(dashboard_root).rglob('OWNERS'):
        import yaml
        data = yaml.safe_load(owners_file.read_text())
        reviewed = data.get('labels', {}).get('reviewed', '')
        if quarters_ago(reviewed, quarter) > threshold:
            stale.append({
                'folder': str(owners_file.parent.relative_to(dashboard_root)),
                'approver': data.get('approvers', ['unknown'])[0],
                'reviewed': reviewed,
                'quarter': quarter,
            })
    return stale

if __name__ == '__main__':
    import argparse, datetime
    p = argparse.ArgumentParser()
    p.add_argument('root')
    p.add_argument('--quarter')
    p.add_argument('--output', default='stale.json')
    args = p.parse_args()
    result = find_stale(args.root, args.quarter)
    Path(args.output).write_text(json.dumps(result, indent=2))
    print(f"{len(result)} stale dashboard folder(s) found")
